if @@admin = 0 and @type = '1' begin
  if @@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@@admin, @@userID, 'Job', 'Edit') = 0 select @type = '0'
end

declare @message nvarchar(4000), @q nvarchar(4000), @duplicate nvarchar(4000), @irregular nvarchar(4000), @field varchar(32), @irregularChars varchar(128), @r int

select @irregularChars = &IrregularValue;
select @duplicate = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> &Job.Nested.Message.v;.' else 'The value of cell <span class="Highlight">%invalidCell</span> is &Job.Nested.Message.e;.' end
select @irregular = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> có chứa các ký tự: ' + @irregularChars else 'The value of cell <span class="Highlight">%invalidCell</span> contains any of the following characters: ' + @irregularChars end

create index i on @@table (ma_vv)

-- Check
if @type = '0' delete @@table where ma_vv in (select ma_vv from dmvv)
select @field = 'ma_vv', @r = min(stt) from @@table where ma_vv like '%[' + @irregularChars + ']%'&Irregular;

-- Checking
&Checking;

select a.* into #k from @@table a join dmvv b on a.ma_vv = b.ma_vv

-- Do not delete following line
-- #OverwriteChecking

if @type = '1' delete @@table where ma_vv in (select ma_vv from #k)

--
select @field = 'ma_vv'
&Job.Nested.Key.b;
  select @q = 'select top 1 @r = a.stt from @@table a, @@table b with (index(i)) where a.ma_vv <> b.ma_vv and a.ma_vv like rtrim(b.ma_vv) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
  select @q = 'select top 1 @r = a.stt from @@table a with (index(i)), dmvv b with (index(PK_dmvv)) where a.ma_vv like rtrim(b.ma_vv) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
  select @q = 'select top 1 @r = b.stt from dmvv a with (index(PK_dmvv)), @@table b with (index(i)) where a.ma_vv like rtrim(b.ma_vv) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
end
-- Insert
&Inserting;
-- Update
if @type = '1' begin &Updating; end
